def guess_number(n: int) -> int:
    # guess(num) is a pre-defined API returning -1, 0, or 1
    left, right = 1, n
    while left <= right:
        mid = (left + right) // 2
        result = guess(mid)  # type: ignore[name-defined]
        if result == 0:
            return mid
        elif result == 1:
            left = mid + 1
        else:
            right = mid - 1
    return -1
